sql:
SELECT MAX(popularity_score) 
FROM characters 
WHERE faction = 'Empire';

SELECT characters.name, roles.role_name
FROM characters
JOIN roles ON characters.role_id = roles.role_id;

external_knowledge:
- "shining stars from the battlefield" refers to the characters with high popularity and performance;
- "sailed beyond the popularity horizon" means having a popularity score greater than 50;
- "standing tall in the realm of PvP" indicates the characters are participating in the PvP game mode;
- "faction flags" refers to the faction each character belongs to;
- "rare essence glowing brightly" alludes to the rarity level of the characters.

sql:
SELECT name 
FROM characters 
WHERE faction = 'Republic';

SELECT name
FROM characters
WHERE role_id = (SELECT role_id FROM characters WHERE name = 'CharacterName');

external_knowledge:
- 'Constellation of stars' symbolizes the roles;
- 'Dazzling light' refers to the number of characters;
- 'Cosmic phenomena' symbolizes factions;
- 'Radiance' represents the popularity score;
- 'Stars' refers to individual characters;
- 'Celestial events' symbolizes the unique factions within roles;
- 'Unique powers' correspond to the count of unique abilities;
- 'Overall brilliance' refers to the average popularity score.

sql:
SELECT characters.name, game_sessions.duration
FROM characters
JOIN game_sessions ON characters.character_id = game_sessions.character_id;

SELECT name
FROM characters
WHERE faction = 'Faction A' AND popularity_score > (
    SELECT AVG(popularity_score)
    FROM characters
);

external_knowledge:
- "shining stars" refers to high-performing characters;
- "captured the hearts of more than eighty percent of the gaming community" translates to a popularity score above 80;
- "thrive in the arena of player versus player battles" refers to the PvP game mode;
- "showcasing their dominance with a performance rating above ninety" means the performance score is above 90.

sql:
SELECT name, popularity_score
FROM characters
WHERE popularity_score = (SELECT MAX(popularity_score) FROM characters);
